$log="C:\`$WINDOWS.~BT\Sources\Panther\setupact.log";$hex=(Get-ItemProperty -Path 'HKLM:\SYSTEM\Setup\MoSetup\Volatile' -Name SetupProgress -ErrorAction SilentlyContinue).SetupProgress.ToString('X');$p=Get-Process Win11Upgrade,Windows10UpgraderApp,SetupHost -ErrorAction SilentlyContinue;$s=Get-Content $log -Tail 200|Select-String "Result value: \[0x0\]";$e=Get-Content $log -Tail 200|Select-String -SimpleMatch "Error";if($p){if($s){Write-Host "`n🟡 Staging success (0x0) but upgrade still running: $($p.ProcessName -join ', ') — Progress(hex): $hex" -f Yellow}else{Write-Host "`n🟢 Upgrade running normally: $($p.ProcessName -join ', ') — Progress(hex): $hex" -f Green}}elseif($s -and -not $p){Write-Host "`n✅ Staging completed successfully (0x0) and no upgrade process running — likely waiting for reboot. — Progress(hex): $hex" -f Green}elseif($e -and -not $p){Write-Host "`n❌ Upgrade process stopped and errors found in setupact.log — rollback or failure likely. — Progress(hex): $hex" -f Red}else{Write-Host "`n⚠️ No active upgrade and no clear success/error markers — possibly idle or cleaned up. — Progress(hex): $hex" -f Yellow}
